var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"앗, 이사장님, 다녀오셨어요?","JPN":"あっ、理事長。お帰りなさい。","ENG":"Oh, Ms. Chairwoman. You're back.","TWN":"喔，理事長回來啦？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 바쁜 일은 다 끝나신 거 맞죠?","JPN":"今日の忙しいお仕事は全部終わったんですよね？","ENG":"You've finished your schedule for the day, right?","TWN":"今天的事情都處理完了嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"응. 테스트는 아직 몇 번 더 거쳐야겠지만 잘 끝났어.","JPN":"うん。まだ何回かテストしないといけないけど、無事に終わったわ。","ENG":"Yes. We'll need to do a few more rounds of testing, but it ended well.","TWN":"嗯，還要再多測試幾次，但今天算是順利結束了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"학생회 업무 때문에 여기 있는 거니? 오늘은 좀 느긋하게 있지.","JPN":"生徒会の仕事でここにいるの？　今日はのんびりしててよかったのに。","ENG":"Are you here on Student Council business? Why don't you take it a little easy today?","TWN":"是學生會有什麼事嗎？你怎麼在這裡？今天怎麼不休息一下？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"헤헤, 마침 저희 모두 이사장님을 기다리고 있었거든요!","JPN":"へへ、ちょうどあたしたちみんなで理事長のことを待ってました！","ENG":"Hehe, we all were waiting for you, Ms. Chairwoman!","TWN":"嘿嘿，我們都在等理事長呢！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오늘 업무 다 끝나셨으면, 저희랑 같이 둘러보지 않으실래요?","JPN":"今日のお仕事が終わったなら、あたしたちと一緒に回りませんか？","ENG":"If you're done with your schedule, could you come with us somewhere?","TWN":"等理事長忙完可以跟我們去個地方嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 업무라면 아직 많이 남아있단다.","JPN":"あはは、お仕事ならまだたくさん残ってるわ。","ENG":"Ah hah hah. But I still have a lot of things left to do.","TWN":"呵呵呵，但我還有很多事沒處理呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"고생하셨습니다 이사장님.","JPN":"お疲れ様でした、理事長。","ENG":"Thank you for all your hard work, Ms. Chairwoman.","TWN":"理事長辛苦了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마침 할로윈 행사가 한창인데 저희랑 같이 어떠신가요?","JPN":"ちょうどハロウィンのイベントが行われていますが、私たちと一緒にいかがですか？","ENG":"The Halloween event is in full swing right now, would you like to join us?","TWN":"剛好正在舉辦萬聖節活動，理事長就和我們一起去看看吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"남은 서류 업무는 저희들이 다 처리해 드렸으니, 걱정하지 마시길.","JPN":"残りの書類業務は私たちが全部片付けましたので、ご心配いりません。","ENG":"We've already taken care of all the leftover paperwork, so don't worry about them.","TWN":"剩下的文書作業我們都處理好了，不用擔心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"뭐?! 너희들이……?","JPN":"ええっ！？　あなたたちが……？","ENG":"What?! All of you...?","TWN":"什麼？！你們……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이사장 업무는 너희들 선에서 해결할 수 있는 게 아냐.","JPN":"理事長の業務はあなたたちで解決できるものじゃないのよ。","ENG":"My work is not something that can be resolved by you.","TWN":"理事長的工作不是你們能夠處理的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"걱정하지 않으셔도 돼요. 중요한 서류는 건드리지 않았거든요.","JPN":"心配しなくても大丈夫ですよ。重要な書類には手を出してないですから。","ENG":"Not to worry. We didn't touch any important documents.","TWN":"理事長請放心，重要的文件我們沒有碰。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에헤헤……. 사실 사고 칠까 봐 못 건든 거지만요.","JPN":"えへへ……実はやらかしちゃいそうで手を出せなかったんですけど。","ENG":"Eh he he... In truth, we couldn't do anything about them in fear of causing trouble.","TWN":"嘿嘿嘿……我們自己也怕會搞砸啦。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"괜찮으시면 저희랑 같이 복실복실 카페에 가보지 않으실래요?","JPN":"よかったらあたしたちと一緒にモフモフカフェに行きませんか？","ENG":"If it's okay with you, would you like to join us in going to the Fluffy Cafe?","TWN":"理事長跟我們一起去毛茸茸咖啡廳嘛？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"화이트래빗 애들이 저번 크리스마스 때보다 더 크게 준비했대요!","JPN":"ホワイトラビットの子たちが、前回のクリスマスより派手に用意したみたいです！","ENG":"The children of White Rabbit seemed to have prepared one bigger than last Christmas!","TWN":"白兔社的人說，這次的活動比上次聖誕節還精彩欸！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"너희들…….","JPN":"みんな……","ENG":"Girls...","TWN":"你們……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"좋아. 모처럼이니까 잠깐 시간 좀 내볼까?","JPN":"いいわ。せっかくだし、ちょっと行ってみようか。","ENG":"All right. I think I can use some time off.","TWN":"好吧，機會難得，我就抽個時間吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"정말 잘 생각하셨습니다.","JPN":"賢明な判断です。","ENG":"Great decision, ma'am.","TWN":"很正確的決定。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"크르릉…….","JPN":"ガルル……","ENG":"Grrrr!!","TWN":"汪汪……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"잘 들어 멍멍이! 널 구해준 게 학생회장이라면서?","JPN":"言うことを聞きなさい、わんこ！　あんたを助けたのは生徒会長でしょう？","ENG":"Now you listen here, puppy! The President rescued you, didn't she?","TWN":"小狗你聽好！救你的人是學生會長好嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"지금 은인인 나를 못 알아보는 거야? 앉으라고! 손!","JPN":"恩人なのに、わからないの？　お座り！　お手！","ENG":"How can you not recognize the person who saved you? Sit! Paw!","TWN":"你現在是把我誤認成你的救命恩人嗎？坐下！握手！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"아, 알았어! 다른 부위라도 좋으니까 말 좀…….","JPN":"わ、わかったから！　少しは私の言うことを……","ENG":"F-fine! Any limb is fine, so could you please–","TWN":"好啦！其他部位也可以，你聽……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"크앙!","JPN":"ガウン！","ENG":"RUFF!","TWN":"汪汪！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"으아아아악!","JPN":"うわあああ！","ENG":"Aaaargh!","TWN":"啊～～～！！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"안 돼 알렉산더! 함부로 사람 무는 거 아냐!","JPN":"ダメ、アレクサンダー！　むやみに人を噛んじゃダメだって！","ENG":"No, Alexander! You shouldn't bite people!","TWN":"不可以喔，亞歷山大！怎麼隨便可以咬人呢！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L43_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"몇 번이나 말했다. 얘 이름은 멍멍이가 아니라 알렉산더라고 말이다.","JPN":"何度も言っているはずだ。こいつの名前はわんこではなく、アレクサンダーだと。","ENG":"I told you several times. His name is not \\"puppy.\\" It's Alexander.","TWN":"本官說過多少次了，牠不叫小狗，牠叫亞歷山大。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"적이 다가오면 확 깨물어버리는 게 알렉산더만의 방침이다!","JPN":"敵が近づくと噛みつくのがアレクサンダーのきまりなんだ！","ENG":"It is Alexander's policy to bite any enemy that approaches him!","TWN":"亞歷山大的戰略就是敵人靠近就咬！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"으악! 알렉산더인지 뭔지 이것 좀 놓으라 그래!","JPN":"わわっ！　アレクサンダーでもなんでもいいから、これ放しなさいよ！","ENG":"Ack! Alex-whatever-you-are! Let go of me!","TWN":"啊啊！亞歷山大還什麼的，你快給我鬆開！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L48_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어설프게 학생회장님 코스프레를 하니까 화내는 거잖아요.","JPN":"中途半端な生徒会長のコスプレなんかするから怒ってるんですよ。","ENG":"He's mad because you did a poor cosplay of the President.","TWN":"誰叫你要扮成學生會長，扮得又不像，牠才會生氣吧。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어흥! 난 은인도 못 알아보는 바보가 아니다! 하고요.","JPN":"ガオン！　僕は恩人の顔もわからないバカじゃない！　ってね。","ENG":"He's saying, \\"Woof! I'm no idiot who can't even recognize my savior!\\"","TWN":"牠內心一定在想，哼！你這個笨蛋！我會認不出救命恩人嗎！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"누구더러 바보라는 거얏!","JPN":"誰にむかってバカって言ってるのよ！","ENG":"Who's calling whom an idiot?!","TWN":"你說誰笨蛋！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"자, 잠깐! 거긴 함부로 무는 데가 아니라고!","JPN":"ちょ、ちょっと！　そこは噛んじゃダメ！","ENG":"W-wait! You shouldn't bite people there!","TWN":"欸欸欸！那邊不能咬啦！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"우리 알렉산더 착하지. 그러면 안 돼요.","JPN":"よしよし、アレクサンダー。そんなことしちゃダメよ。","ENG":"There, there, Alexander. Don't do that.","TWN":"亞歷山大乖乖，不可以咬人喔。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"PUPPY_EXTRA_NULL_NULL","text":{"KOREA":"왕!","JPN":"ワン！","ENG":"Woof!","TWN":"汪！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_ANIMAL_D2"},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"사, 살았다…….","JPN":"た、助かった……","ENG":"P-phew...","TWN":"得救了……"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗. 우리 알렉산더는 정말 순하고 착해. 나이엘이랑 잘 놀고 있었니?","JPN":"ふふっ。アレクサンダーは本当に大人しくていい子だわ。ナイエルと楽しく遊んでいたの？","ENG":"Ha ha. Alexander is such a good dog. Were you playing with Naielle?","TWN":"呵呵，亞歷山大好乖喔～你剛是在跟奈爾玩嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"저게 어딜 봐서 순하다는 건데?!","JPN":"あれのどこか大人しいっていうのよ！？","ENG":"How's that a good dog?!","TWN":"牠到底哪裡乖啦？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘, 네가 여기 웬일이야? 그 복장은 또 뭐고?","JPN":"ナイエル、ここで何をしてるの？　その格好は何？","ENG":"Naielle, what are you doing here? And what's with that outfit?","TWN":"奈爾，你在這裡幹嘛？而且你那身打扮是怎麼回事？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어제 나이엘이 소인과 내기를 하자 했었소.","JPN":"昨日、ナイエルと自分が賭けをしました。","ENG":"Yesterday, Naielle made a bet with me.","TWN":"昨日奈爾與在下打賭。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"승부에서 진 자가 이긴 사람이 준 옷을 입는 내기였지.","JPN":"勝負で負けた者が、勝った者が指定する服を身にまとう賭けでした。","ENG":"The loser has to wear something the winner chose.","TWN":"輸家要穿贏家給的衣服。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이건 옌의 옷이니, 나이엘도 기쁘게 입어줄 거라 생각하오.","JPN":"これはイェンの服ですので、ナイエルも喜んでいると思います。","ENG":"These are Yen's clothes, and I thought Naielle would be happy to wear them.","TWN":"這是嫣杏的衣服，在下以為奈爾穿起來也會很好看。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"크윽……. 하나도 안 기쁘거든?! 하필이면 이런 민망한 옷을 입히다니……!","JPN":"くうっ……全然嬉しくないんだけど！？　よりによってこんな恥ずかしい服を……！","ENG":"Kgh... I'm not happy one bit! You just had to pick the most embarrassing outfit...!","TWN":"呃……一點也不欸？！誰會穿這種丟人的衣服……！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"민망……?","JPN":"恥ずかしい……？","ENG":"Embarrassing...?","TWN":"丟人嗎……？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"오늘의 치욕… 반드시 기억해 두겠어!","JPN":"今日の屈辱……絶対忘れないよ！","ENG":"I won't forget... the shame you gave me today!","TWN":"我不會忘記…今天的羞辱的！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"다음엔 너한테 <color=#ffd34c>엄청 부끄러운 옷</color>을 입히고 말 테다!","JPN":"次はあんたに<color=#ffd34c>めちゃくちゃ恥ずかしい服</color>を着せてやるんだから！","ENG":"I'll make sure to make you wear <color=#ffd34c>something super embarrassing</color>!","TWN":"下次我一定會讓你穿上<color=#ffd34c>超級羞恥的衣服</color>的！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"도전이라면 언제든지 받아 주리다.","JPN":"挑戦ならいつでも受けて立ちます。","ENG":"I shall accept your challenge anytime.","TWN":"歡迎隨時下戰帖。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"나이엘은 강하고 성실하니, 언젠간 소인을 뛰어넘을 수도 있겠구려.\xA0","JPN":"ナイエルは強くて真面目ですので、いつか自分を越えるかもしれません。\xA0","ENG":"You're strong and diligent, so I believe you will surpass me one day, Naielle.\xA0","TWN":"奈爾能力好又忠心，總有一天可以超越在下的。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"……후훗.","JPN":"……ふふっ。","ENG":"...Ha ha.","TWN":"……呵呵。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"서, 설마 이런 내 모습을 비웃으려 온 건 아니겠지?!","JPN":"ま、まさか私のこんな姿を笑うために来たわけじゃないよね！？","ENG":"Y-you're not laughing at me because of what I'm wearing, are you?!","TWN":"你，你們該不會是特意來看我笑話的吧？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그럴리가 있니.","JPN":"そんなはずないわ。","ENG":"How could I?","TWN":"怎麼可能。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"오늘 널 보니까 빨리 친한 친구한테 소개해 주고 싶었을 뿐이야.","JPN":"今日あなたを見たら、早く親友に紹介してあげたくて。","ENG":"I just thought I wanted to introduce you to a close friend of mine.","TWN":"我只是想趕快把你介紹給我的朋友而已。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"치, 친구……?!","JPN":"し、親友……！？","ENG":"F-friend...?!","TWN":"理事長的…朋友…？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"이사장의 친구면 초일류 테스크포스의 사장 정도는 되는 거 아냐?!","JPN":"理事長の友だちって、超一流タスクフォースの社長とかじゃない！？","ENG":"Aren't your friends all, like, CEOs of a top-class TASKFORCE?!","TWN":"理事長的朋友應該都是特異功能特遣勢力的老闆吧？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"언제든지 환영이지! 그럼 미팅은 언제쯤으로……?","JPN":"いつでも歓迎だよ！　じゃあ、ミーティングはいつ……？","ENG":"Please do! So, when can I expect to meet your friend...?","TWN":"好欸！快把我介紹給他們！什麼時候約見面……？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하, 지금은 조금 곤란한데……. 나중에 꼭 불러줄게.","JPN":"あはは、今はちょっと困るけど……そのうち呼んであげるね。","ENG":"Ah hah hah. Right now's not a good time... But I'll set up something later.","TWN":"哈哈哈，現在不太方便……之後再找你。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"아니, 실컷 기대하게 해놓고선?!","JPN":"いや、期待させておいてそれだけ！？","ENG":"Ugh, then why did you bring it up and get me all excited?!","TWN":"什麼嘛，幹嘛吊人家胃口？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"호진아. 주문해도 될까? 여기 학생회 언니들이 먹을 것도.","JPN":"マユミさん。注文していいかしら？　ここの生徒会の分も。","ENG":"Hojin, can we order? Mine and the Student Council members.","TWN":"鎬眞，可以幫我們點餐嗎？還有學生會的學姊們。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"네, 물론이죠!","JPN":"はい、もちろんです！","ENG":"Yes, absolutely!","TWN":"好的，馬上來！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이사장님. 테스트 때 일입니다만, 예고도 없이 통신을 끊게 되어 죄송합니다.","JPN":"理事長。テストでの出来事ですが、予告もなく通信を切ってしまって申し訳ありません。","ENG":"Ms. Chairwoman. I apologize for cutting the connection without notice during the previous test.","TWN":"理事長，雖然是測試期間的事情，但沒有跟理事長報告就擅自中斷通訊，實在很抱歉。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"친구분들께서 방해 없이 셋이서만 진행하고 싶다고 양해를 구하셨거든요.","JPN":"ご友人の方々から、他からの邪魔なく3人だけで進行したいと言われましたので。","ENG":"Your friends asked for my understanding that they wanted to proceed with just the three of you without any interruption.","TWN":"因為理事長的朋友跟我說，希望你們三個可以在不受到任何打擾的情況下進行測試。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"신경 쓰지 마. 덕분에 너무 즐거웠단다.","JPN":"気にしないで。おかげでとても楽しかったわ。","ENG":"Don't worry about it. I had a great time, thanks to you.","TWN":"別在意，托你的福，我玩得非常開心。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이러니까 마치 학생 시절로 돌아간 것만 같네.","JPN":"こうしてるとまるで学生時代に戻ったみたいね。","ENG":"I felt like I was transported back in time to when I was a student.","TWN":"彷彿回到學生時代一樣。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"솔직히……. 앞으로도 계속 이랬으면 좋겠어.","JPN":"正直……これからもこのままだったらいいのに。","ENG":"Honestly... I wished that it stayed like that.","TWN":"老實說……真希望以後也能繼續這樣。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아하하……. 칠칠치 못한 모습 보여줘서 미안해.","JPN":"あはは……だらしない姿を見せてごめんね。","ENG":"Ah hah hah... I'm sorry for being unprofessional.","TWN":"哈哈哈……對不起，讓你看到我這麼沒用的一面。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"이러니까 누가 학생이고 어른인지 모르겠는걸?","JPN":"こうしてると、誰が生徒で誰が大人なのかわからないわよね？","ENG":"Now, I can't tell who's the student and who's the adult.","TWN":"真不知道我們誰是學生，誰是大人呢？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"옌은 소질이 있어. 나중에 크면 교수직으로 채용하고 싶을 정도로.","JPN":"イェンは素質がある。この先成長したら、教授として採用したいくらい。","ENG":"Yen, you have potential. So much that I want to hire you as a professor once you get older.","TWN":"嫣杏你很有潛力，等你長大，我都想請你來當教授呢。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"과찬이세요.","JPN":"褒めすぎです。","ENG":"That's too much of a praise, ma'am.","TWN":"理事長過獎。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"주문하신 음료하고 디저트 13종류 나왔습니다!","JPN":"ご注文の飲み物とデザートの13種類、どうぞ！","ENG":"Here are your drinks and the thirteen types of desserts you ordered!","TWN":"這是你們點的飲料和13種甜點！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_SHAKING_COCK"},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이, 이건……?","JPN":"こ、これは……？","ENG":"Th-this is...","TWN":"這，這是……？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"내가 주문했소. 이곳에서만 먹을 수 있다는 맛이길래 궁금했다오.","JPN":"自分が注文しました。ここだけでしか味わえないらしいので、気になっていたのです。","ENG":"I ordered them. They told me I could only have them here, and was curious how they tasted.","TWN":"是在下點的。聽說是只有這裡才吃得到的味道，所以就覺得很好奇。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저, 정말 이걸 다 먹을 수 있는 거야?","JPN":"ほ、本当にこれ全部食べられるの？","ENG":"C-can you really eat all of them?","TWN":"吃，吃得完嗎？"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"음식을 남기는 실책은 저지르지 않을 테니 걱정하지 마시오.","JPN":"食べ物を粗末にはしないので、ご心配無用です。","ENG":"I will not make the mistake of wasting food, so do not worry.","TWN":"請放心，在下絕對不會犯下浪費食物的錯誤。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"남은 건 포장하면 되니까 너무 무리하지 마렴.","JPN":"残った食べ物は持ち帰ったらいいから、あまり無理しないで。","ENG":"You can take home the rest, so don't force yourself to eat them all.","TWN":"吃不完就打包，不要勉強。"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"으악! 이 못된 멍멍이! 왜 내 것만 뺏어가는 건데?!","JPN":"わあっ！　このわんこ！　どうして私の分だけ食べちゃうんだよ！？","ENG":"Agh! Bad puppy! Why are you only stealing mine?!","TWN":"可惡！你這隻壞狗狗！為什麼只搶我的？！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_03"},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"야! 거기서!","JPN":"こらっ！　待ちなさい！","ENG":"Hey! Stop right there!","TWN":"喂！站住！"},"stage":{"bg":"RESTAURANT_01","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"}]`);export{e as default};